// Calcule le trimestre precedent
const now = new Date();
const currentMonth = now.getMonth(); // 0-11
// Trimestre precedent = mois courant - 3
const startMonth = Math.floor(currentMonth / 3) * 3 - 3;
const year = startMonth < 0 ? now.getFullYear() - 1 : now.getFullYear();
const realStart = (startMonth + 12) % 12;
const start = new Date(year, realStart, 1);
const end = new Date(year, realStart + 3, 1);
const quarterName = `Q${Math.floor(realStart / 3) + 1} ${year}`;
return [{ json: {
  from_iso: start.toISOString(),
  to_iso: end.toISOString(),
  quarter: quarterName,
  deadline: `${now.getDate()}/${now.getMonth() + 1}/${now.getFullYear()}`
} }];

const profiles = items[0].json || [];
const sales = $('Fetch Sales Quarter').first().json || [];
const quarter = $('Compute Quarter').first().json.quarter;
const results = [];
for (const profile of profiles) {
  if (!profile.email) continue;
  const userSales = sales.filter(s => s.user_id === profile.id);
  const totalCommission = userSales.reduce((sum, s) => sum + (Number(s.commission_amount) || 0), 0);
  const rate = Number(profile.urssaf_rate) || 0.22;
  const totalUrssaf = totalCommission * rate;
  results.push({
    json: {
      user_id: profile.id,
      email: profile.email,
      full_name: profile.full_name || 'Alison',
      business_name: profile.business_name || 'Visit & Smile',
      quarter,
      nb_ventes: userSales.length,
      total_commission: totalCommission.toFixed(2),
      total_urssaf: totalUrssaf.toFixed(2),
      rate_pct: (rate * 100).toFixed(1)
    }
  });
}
return results;

